import { defineTool } from '@flue/runtime'
import * as v from 'valibot'
import { db } from '../lib/db.ts'

export const introspectSchema = defineTool({
  name: 'introspect_schema',
  description:
    'Lists the database tables and their columns so you can write correct SQL.',
  parameters: v.object({}),
  execute: async () => {
    const tables = await db.execute(
      "SELECT name FROM sqlite_master WHERE type = 'table' AND name NOT LIKE 'sqlite_%'"
    )
    const schema: Record<string, unknown> = {}
    for (const row of tables.rows) {
      const name = String(row.name)
      const info = await db.execute(`PRAGMA table_info(${name})`)
      schema[name] = info.rows.map((c) => ({ name: c.name, type: c.type }))
    }
    return JSON.stringify(schema, null, 2)
  },
})

import { defineTool } from '@flue/runtime'
import * as v from 'valibot'
import { db } from '../lib/db.ts'

export const runQuery = defineTool({
  name: 'run_query',
  description: 'Executes a read-only SELECT query and returns the rows as JSON.',
  parameters: v.object({
    sql: v.string(),
  }),
  execute: async ({ sql }) => {
    if (!/^\s*select/i.test(sql)) {
      return 'Refused: only read-only SELECT queries are allowed.'
    }
    const result = await db.execute(sql)
    return JSON.stringify(result.rows, null, 2)
  },
})

import { createClient } from '@libsql/client'

/**
 * Database client. Defaults to a local SQLite file; point DATABASE_URL at a
 * remote Turso/libSQL database, or swap the client for Postgres/MySQL.
 */
export const db = createClient({
  url: process.env.DATABASE_URL ?? 'file:data.db',
})
